// Generated by OrchestKit Claude Plugin
// Created: 2026-06-10

/**
 * Worktree Provisioner — WorktreeCreate hook (#2335)
 *
 * Current CC contract (code.claude.com/docs/en/hooks, WorktreeCreate): a
 * registered WorktreeCreate hook OWNS provisioning. It must create the
 * worktree itself and return its absolute path — command-type hooks echo a
 * bare path on stdout (emitted centrally by run-hook.mjs), http-type hooks
 * return `hookSpecificOutput.worktreePath`. Empty stdout is a HARD FAILURE
 * that aborts the Agent(isolation:"worktree") spawn. There is no
 * observation-only mode and matchers are silently ignored.
 *
 * This inverts the #1990/#2016 assumption ("emit empty stdout and CC
 * provisions at its default path"). Returning a path we provisioned is safe
 * on BOTH contracts: older CC treats non-empty stdout as "use this path",
 * current CC requires it.
 *
 * Absorbs the two prior WorktreeCreate observers:
 *  - worktree-lifecycle-logger's create-side monorepo sparsePaths advisory
 *    (the logger keeps its WorktreeRemove role) — and since we now own
 *    provisioning, `worktree.sparsePaths` is honored for real via
 *    `git worktree add --no-checkout` + `git sparse-checkout set`.
 *  - enter-registrar's children-bus init + worktree_links pending marker,
 *    now written AFTER successful provisioning. The old order pre-created
 *    `.worktrees/<name>/children/` before the worktree existed, leaving
 *    orphan shells behind on every failed spawn.
 *
 * Hook event: WorktreeCreate (sync — CC consumes this hook's stdout).
 */

import type { HookContext, HookInput, HookResult } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { childrenDir } from '../lib/children-bus.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { safeIdentifier } from '../lib/safe-fs.js';
import { getSparsePaths, maybeEmitMonorepoAdvisory } from '../lib/monorepo-advisory.js';
import { execFileSync } from 'node:child_process';
import { existsSync, mkdirSync, readdirSync, realpathSync, rmSync, statSync } from 'node:fs';
import { join, resolve } from 'node:path';

/**
 * Canonicalize a path for registry comparison. `git worktree list` reports
 * realpaths (e.g. /private/var/... on macOS) while joined input paths may go
 * through symlinks (/var/...) — plain resolve() would never match.
 */
function canon(p: string): string {
  try {
    return realpathSync(p);
  } catch {
    return resolve(p);
  }
}

const HOOK_NAME = 'worktree/worktree-provisioner';

/** Bound git operations well under the hooks.json timeout (30s). */
const GIT_TIMEOUT_MS = 25_000;

/**
 * Branch names come from untrusted hook input. execFileSync already prevents
 * shell injection (args are never shell-interpreted), but constrain to git's
 * sane charset anyway so a hostile value can't smuggle option-like tokens.
 */
const SAFE_BRANCH = /^[A-Za-z0-9][\w./-]*$/;

function git(cwd: string, args: string[]): string {
  return execFileSync('git', ['-C', cwd, ...args], {
    encoding: 'utf8',
    timeout: GIT_TIMEOUT_MS,
    windowsHide: true,
    stdio: ['ignore', 'pipe', 'pipe'],
  });
}

/** Absolute paths registered in `git worktree list`, or null if git failed. */
function registeredWorktrees(projectDir: string): Set<string> | null {
  try {
    const stdout = git(projectDir, ['worktree', 'list', '--porcelain']);
    const paths = new Set<string>();
    for (const line of stdout.split('\n')) {
      if (line.startsWith('worktree ')) {
        paths.add(canon(line.slice('worktree '.length).trim()));
      }
    }
    return paths;
  } catch {
    return null;
  }
}

/** True if `branch` exists as a local branch in the repo. */
function branchExists(projectDir: string, branch: string): boolean {
  try {
    git(projectDir, ['rev-parse', '--verify', '--quiet', `refs/heads/${branch}`]);
    return true;
  } catch {
    return false;
  }
}

/**
 * True if `path` holds no content beyond empty dirs and placeholder files —
 * i.e. it is an orphan shell from a failed prior spawn (the pre-#2335
 * enter-registrar created `.worktrees/<name>/children/.gitkeep` BEFORE the
 * worktree existed). Bounded to 3 levels; unknown depth counts as non-empty.
 */
function isOrphanShell(path: string, depth = 0): boolean {
  if (depth > 3) return false;
  let entries: string[];
  try {
    entries = readdirSync(path);
  } catch {
    return false;
  }
  for (const entry of entries) {
    if (entry === '.DS_Store' || entry === 'Thumbs.db' || entry === '.gitkeep') continue;
    const full = join(path, entry);
    let st: ReturnType<typeof statSync>;
    try {
      st = statSync(full);
    } catch {
      continue;
    }
    if (st.isFile() || st.isSymbolicLink()) return false;
    if (st.isDirectory() && !isOrphanShell(full, depth + 1)) return false;
  }
  return true;
}

/** Run `git worktree add` honoring branch/detach input and sparsePaths. */
function provision(
  projectDir: string,
  worktreePath: string,
  input: HookInput,
  ctx: HookContext,
): void {
  const sparsePaths = getSparsePaths(projectDir);
  const addArgs = ['worktree', 'add'];
  if (sparsePaths) addArgs.push('--no-checkout');

  const branch = typeof input.branch === 'string' && SAFE_BRANCH.test(input.branch)
    ? input.branch
    : null;

  if (input.detach === true || !branch) {
    // No (usable) branch requested — detached copy of HEAD, CC's historical
    // default for agent isolation.
    addArgs.push('--detach', worktreePath);
  } else if (branchExists(projectDir, branch)) {
    addArgs.push(worktreePath, branch);
  } else {
    addArgs.push('-b', branch, worktreePath);
  }

  git(projectDir, addArgs);

  if (sparsePaths) {
    git(worktreePath, ['sparse-checkout', 'set', ...sparsePaths]);
    git(worktreePath, ['checkout']);
    ctx.log(HOOK_NAME, `sparse checkout applied (${sparsePaths.length} path(s))`);
  }
}

/** children-bus init + pending-link marker — ONLY after successful creation. */
function registerLinks(
  projectDir: string,
  worktreePath: string,
  name: string,
  parentSid: string,
  ctx: HookContext,
): void {
  try {
    const dir = childrenDir(worktreePath);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true, mode: 0o700 });
    const gitkeep = join(dir, '.gitkeep');
    if (!existsSync(gitkeep)) atomicWriteSync(gitkeep, '');
  } catch (err) {
    ctx.log(HOOK_NAME, `children-bus init failed: ${(err as Error).message}`);
  }

  try {
    const pendingDir = join(projectDir, '.claude', 'state', 'worktree-pending');
    const pendingPath = join(pendingDir, `${name}.json`);
    const payload = JSON.stringify({
      parent_sid: parentSid,
      worktree_path: worktreePath,
      name,
      created_at: Math.floor(Date.now() / 1000),
    });
    atomicWriteSync(pendingPath, payload);
  } catch (err) {
    ctx.log(HOOK_NAME, `pending marker write failed: ${(err as Error).message}`);
  }
}

export function worktreeProvisioner(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  // CC sends `worktree_name` (documented field); older builds sent `name`.
  // safeIdentifier() guards envelope-corrupt values per #1826/#1250. The
  // fallback must be unique — a fixed 'unknown' would make two concurrent
  // nameless spawns share one worktree.
  const rawName = (input.worktree_name as string | undefined) ?? input.name;
  const name = safeIdentifier(rawName, `wt-${Date.now().toString(36)}`);
  const projectDir = input.project_dir || process.cwd();
  const worktreePath = join(projectDir, '.worktrees', name);

  const registered = registeredWorktrees(projectDir);
  if (registered === null) {
    // Git itself is unhealthy — we cannot provision. Decline (empty stdout):
    // older CC falls back to its default creation; current CC fails the
    // isolation request, which is accurate.
    ctx.log(HOOK_NAME, 'declining — `git worktree list` failed; cannot provision');
    return outputSilentSuccess();
  }

  if (registered.has(canon(worktreePath))) {
    // Already a registered worktree (idempotent re-fire) — just return it.
    ctx.log(HOOK_NAME, `worktree already registered: ${worktreePath}`);
    return {
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: { worktreePath },
    };
  }

  // Self-heal: a failed pre-#2335 spawn left an unregistered orphan shell at
  // exactly this path, which would make `git worktree add` fail.
  if (existsSync(worktreePath)) {
    if (isOrphanShell(worktreePath)) {
      try {
        rmSync(worktreePath, { recursive: true, force: true });
        ctx.log(HOOK_NAME, `removed orphan shell at ${worktreePath}`);
      } catch (err) {
        ctx.log(HOOK_NAME, `orphan shell removal failed: ${(err as Error).message}`);
        return outputSilentSuccess();
      }
    } else {
      ctx.log(HOOK_NAME, `declining — ${worktreePath} exists with content but is not a registered worktree`);
      return outputSilentSuccess();
    }
  }

  try {
    provision(projectDir, worktreePath, input, ctx);
  } catch (err) {
    ctx.log(HOOK_NAME, `git worktree add failed: ${(err as Error).message}`);
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `provisioned worktree: ${worktreePath}`);

  // Observability side-effects — strictly after successful creation, all
  // best-effort: the provisioned path must be returned even if these fail.
  const parentSid = input.session_id;
  if (parentSid) registerLinks(projectDir, worktreePath, name, parentSid, ctx);
  maybeEmitMonorepoAdvisory(projectDir, name, ctx, HOOK_NAME);

  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: { worktreePath },
  };
}
